Type Element = Enregistrement
Debut
    val  : Entier;
    suiv : ^Element;
Fin;

Type Pile = Enregistrement
Debut
    sommet : ^Element;
Fin;

Procedure Init(Var P : Pile)
Debut
    P.sommet := NIL;
Fin;

Procedure Empiler(Var P : Pile, v : Entier)
Var n : ^Element;
Debut
    n := allouer(taille(Element));
    n->val := v;
    n->suiv := P.sommet;
    P.sommet := n;
Fin;

Procedure Depiler(Var P : Pile, Var v : Entier)
Var t : ^Element;
Debut
    t := P.sommet;
    v := t->val;
    P.sommet := t->suiv;
    liberer(t);
Fin;

